function solve(nums: number[], queries: number[][]): number[] {
    // Precompute the popcount-depth for each number in nums
    const popcountDepth: number[] = nums.map(num => {
        let depth = 0;
        let current = num;
        while (current !== 1) {
            current = countSetBits(current);
            depth++;
        }
        return depth;
    });

    // Function to count the number of set bits (1s) in the binary representation of a number
    function countSetBits(n: number): number {
        let count = 0;
        while (n) {
            n &= n - 1; // Clear the least significant set bit
            count++;
        }
        return count;
    }

    // For efficient range queries and updates, we use a segment tree
    // Since k can only be up to 5, we can use a 2D array for each k
    // We'll use a Binary Indexed Tree (Fenwick Tree) for each k
    const maxK = 5;
    const bitTrees: number[][] = Array.from({ length: maxK + 1 }, () => new Array(nums.length + 1).fill(0));

    // Initialize the BITs
    for (let i = 0; i < nums.length; i++) {
        const depth = popcountDepth[i];
        if (depth <= maxK) {
            bitTrees[depth][i + 1] = 1;
            for (let j = i + 1; j <= nums.length; j += j & -j) {
                bitTrees[depth][j] += 1;
            }
        }
    }

    // Function to update the BIT for a given index and value
    function updateBIT(k: number, index: number, delta: number) {
        if (k > maxK) return;
        while (index <= nums.length) {
            bitTrees[k][index] += delta;
            index += index & -index;
        }
    }

    // Function to query the BIT for a given index
    function queryBIT(k: number, index: number): number {
        if (k > maxK) return 0;
        let res = 0;
        while (index > 0) {
            res += bitTrees[k][index];
            index -= index & -index;
        }
        return res;
    }

    // Function to query the range [l, r] for a given k
    function rangeQuery(k: number, l: number, r: number): number {
        if (k > maxK) return 0;
        return queryBIT(k, r + 1) - queryBIT(k, l);
    }

    // Process the queries
    const answer: number[] = [];
    for (const query of queries) {
        if (query[0] === 1) {
            const [l, r, k] = query.slice(1);
            const count = rangeQuery(k, l, r);
            answer.push(count);
        } else {
            const [idx, val] = query.slice(1);
            const oldVal = nums[idx];
            const oldDepth = popcountDepth[idx];
            const newVal = val;
            const newDepth = popcountDepth[idx] = computePopcountDepth(newVal);
            // Update the BITs
            updateBIT(oldDepth, idx + 1, -1);
            updateBIT(newDepth, idx + 1, 1);
            nums[idx] = newVal;
        }
    }

    return answer;
}

