fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    // Precompute the popcount-depth for each number in nums
    let mut popcount_depth: Vec<usize> = nums.iter().map(|&num| {
        let mut depth = 0;
        let mut current = num;
        while current != 1 {
            current = count_set_bits(current);
            depth += 1;
        }
        depth
    }).collect();

    // Function to count the number of set bits (1s) in the binary representation of a number
    fn count_set_bits(n: i64) -> usize {
        let mut count = 0;
        let mut num = n;
        while num != 0 {
            num &= num - 1;
            count += 1;
        }
        count
    }

    // Since k can only be up to 5, we can use a 2D array for each k
    // We'll use a Binary Indexed Tree (Fenwick Tree) for each k
    const MAX_K: usize = 5;
    let mut bit_trees: Vec<Vec<usize>> = vec![vec![0; nums.len() + 1]; MAX_K + 1];

    // Initialize the BITs
    for i in 0..nums.len() {
        let depth = popcount_depth[i];
        if depth <= MAX_K {
            bit_trees[depth][i + 1] = 1;
            let mut j = i + 1;
            while j <= nums.len() {
                bit_trees[depth][j] += 1;
                j += j & -j;
            }
        }
    }

    // Function to update the BIT for a given index and value
    fn update_bit(k: usize, index: usize, delta: isize, bit_trees: &mut Vec<Vec<usize>>) {
        if k > MAX_K {
            return;
        }
        let mut i = index;
        while i <= bit_trees[k].len() as usize {
            bit_trees[k][i] += delta as usize;
            i += i & -i;
        }
    }

    // Function to query the BIT for a given index
    fn query_bit(k: usize, index: usize, bit_trees: &Vec<Vec<usize>>) -> usize {
        if k > MAX_K {
            return 0;
        }
        let mut res = 0;
        let mut i = index;
        while i > 0 {
            res += bit_trees[k][i];
            i -= i & -i;
        }
        res
    }

    // Function to query the range [l, r] for a given k
    fn range_query(k: usize, l: usize, r: usize, bit_trees: &Vec<Vec<usize>>) -> usize {
        if k > MAX_K {
            return 0;
        }
        query_bit(k, r + 1, bit_trees) - query_bit(k, l, bit_trees)
    }

    // Process the queries
    let mut answer: Vec<i64> = Vec::new();
    for query in queries {
        if query[0] == 1 {
            let [_, l, r, k] = &query[1..];
            let count = range_query(*k as usize, *l as usize, *r as usize, &bit_trees);
            answer.push(count as i64);
        } else {
            let [idx, val] = &query[1..];
            let old_val = nums[*idx as usize];
            let old_depth = popcount_depth[*idx as usize];
            let new_val = *val;
            let new_depth = compute_popcount_depth(new_val);
            popcount_depth[*idx as usize] = new_depth;

            // Update the BITs
            update_bit(old_depth, *idx as usize + 1, -1, &mut bit_trees);
            update_bit(new_depth, *idx as usize + 1, 1, &mut bit_trees);
            nums[*idx as usize] = new_val;
        }
    }

    answer
}

